	"tendering/view/View1.view.xml":'<mvc:View controllerName="tendering.controller.View1"\n    xmlns:mvc="sap.ui.core.mvc"\n    xmlns="sap.m"\n    xmlns:l="sap.ui.layout"\n    xmlns:core="sap.ui.core"><Page id="page" title="{i18n>title}"><VBox id="_IDGenVBox1" class="sapUiSmallMargin sapUiContentPadding" alignItems="Center" justifyContent="Center" height="100%"><Panel id="_IDGenPanel"\n            width="400px"\n            class="sapUiResponsiveMargin"\n            backgroundDesign="Solid"\n            headerText="Enter Quotation Details:"\n           ><content><VBox id="_IDGenVBox2" class="sapUiSmallMargin"><Label id="_IDGenLabel2" text="Quotation Number" required="true" design="Bold"/><Input id="quotationInput" showValueHelp="true" valueHelpRequest=".onValueHelpRequest"\n                           placeholder="Enter or select quotation number"\n                           valueState="None" class="sapUiSmallMarginBottom" submit="onQuotationSubmit"/><Label id="_IDGenLabel" text="Select Item Number" required="true" /><Select\n    id="_IDGenSelect"\n    width="100%"\n    selectedKey="{/SelectedItemNumber}"\n    items="{\n        path: \'/documentItems\'\n    }"><core:Item id="_IDGenItem"\n        key="{SalesQuotationItem}"\n        text="{SalesQuotationItem}::{SalesQuotationItemText}" /></Select><Text id="_IDGenText" text="{/ErrorMessage}" visible="{= !!${/ErrorMessage} }" /><Button id="_IDGenButton"\n                        text="Next"\n                        type="Emphasized"\n                        press=".onNextPress"\n                        class="sapUiTinyMarginTop"/></VBox></content></Panel></VBox></Page></mvc:View>'
